begin;

values ('1marketph', '1marketph', true)
on conflict (id) do update set public = excluded.public;

create table if not exists public."1marketph" (
  id uuid primary key default gen_random_uuid(),
  entity_name text not null,
  legacy_id text,
  title text,
  user_email text,
  data jsonb not null default '{}'::jsonb,
  media_urls text[] not null default '{}',
  created_at timestamptz,
  updated_at timestamptz,
  imported_at timestamptz not null default now(),
  unique(entity_name, legacy_id)
);

create index if not exists idx_1marketph_entity_name on public."1marketph" (entity_name);
create index if not exists idx_1marketph_data_gin on public."1marketph" using gin (data);

